// generar_249_medicamento_tomas.js
// CHIQUI Entre Señales — Fix duplicados de medicamentos + historial de tomas
//
// IMPORTANTE: primero corre sql_249_medicamento_tomas.sql en Supabase
// (New snippet). Ese SQL:
//   1) Crea la tabla medicamento_tomas con RLS por user_id.
//   2) Limpia los duplicados existentes: los medicamentos repetidos
//      con el mismo nombre pasan a estado 'finalizado' con nota
//      "[Migrado: era duplicado, tomas conservadas]", y sus fechas de
//      inicio se convierten en tomas del medicamento original.
//   3) Índice UNIQUE(medicamento_id, fecha) previene tomas repetidas.
//
// El PROBLEMA que corrige:
// Cada vez que el usuario marcaba "💊 Recibió medicamento" en el
// registro diario, se creaba un medicamento NUEVO en la tabla
// medicamentos. Efecto: 3 días registrando = 3 Rimadyl duplicados.
// La novedad del dashboard leía "3 medicamentos activos" y decía
// "¿Le diste el medicamento a Luna? (Rimadyl y Rimadyl y Rimadyl)".
//
// LA SOLUCIÓN separa dos acciones que estaban mezcladas:
//   TRATAMIENTO (medicamentos): se crea UNA vez.
//   TOMA DIARIA (medicamento_tomas): una fila por día de administración.
//
// Qué cambia en la UI:
//
// 1) Registro diario, "💊 Recibió medicamento":
//    - Si HAY medicamentos activos, el mini-modal muestra la lista
//      con checks (radio-buttons visuales) y pide al usuario elegir
//      cuál le dio hoy. Al confirmar → INSERT en medicamento_tomas
//      (sin duplicar el tratamiento). Si toca dos veces por accidente,
//      el UNIQUE(medicamento_id, fecha) del SQL previene la doble toma.
//    - Botón "＋ Es un medicamento nuevo" abre el formulario clásico
//      para crear el tratamiento + su primera toma.
//    - Si NO hay medicamentos activos, va directo al formulario nuevo.
//    - Vacunas y antiparasitarios siguen igual (esos SÍ son puntuales
//      por definición, no se repiten diario).
//
// 2) Novedad del dashboard "¿Le diste el medicamento?":
//    - Ahora se calcula por medicamento_id: solo los activos que NO
//      tienen toma hoy generan la novedad. Si el usuario ya marcó
//      Rimadyl hoy, la novedad desaparece para ese medicamento; si
//      además está tomando Meloxicam, seguirá recordando ese.
//
// 3) Prevención, tarjeta de cada medicamento:
//    - Bajo la nota (si existe) aparece "N tomas registradas" con las
//      últimas 3 fechas como píldoras. Botón "Ver todas (N)" expande
//      el historial completo. Datos que hasta ahora estaban perdidos
//      dentro de duplicados ahora se ven ordenados por tratamiento.
//
// Uso:
//   1) SQL primero: sql_249_medicamento_tomas.sql → New snippet → Run
//   2) node generar_249_medicamento_tomas.js
//   3) git add . && commit && push

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "app/registro-diario/page.tsx",
    base64: ""
  },
  {
    ruta: "app/dashboard/page.tsx",
    base64: ""
  },
  {
    ruta: "app/prevencion/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('\nListo. 3 archivos escritos.')
  console.log('Recuerda: SQL primero, luego git add / commit / push.')
} else {
  console.error('\nTerminó con ' + errores + ' error(es). NO hagas push.')
  process.exit(1)
}
